#include <stdlib.h>
#include <string.h>

char *duplicate(const char *src) {
    size_t len = strlen(src);
    char *buf = (char *)malloc(len + 1);
    strcpy(buf, src);
    return buf;
}

void process(const char *input) {
    char *copy = duplicate(input);
    char *other = (char *)malloc(256);
    strcpy(other, copy);
    free(copy);
    // BUG: use-after-free (copy was freed)
    other[0] = copy[0];
    free(other);
}

int main() {
    process("hello world");
    return 0;
}

